import { useCallback, useLayoutEffect, useRef, useState } from 'preact/hooks';
import type { RefObject } from 'preact';

type UseMiddleEllipsisResult = {
  ref: RefObject<HTMLElement>;
  truncatedText: string;
};

const parsePixelSize = (value: string): number | null => {
  const trimmed = value.trim();
  if (!trimmed || trimmed === 'none' || trimmed === 'auto') return null;
  if (!trimmed.endsWith('px')) return null;
  const parsed = parseFloat(trimmed);
  return Number.isFinite(parsed) ? parsed : null;
};

// Hook that returns a ref to attach to the parent container and a truncated string
// with the ellipsis placed in the middle. The hook recalculates when the container
// width or the input text changes.
const useMiddleEllipsis = <E extends HTMLElement = HTMLElement>(
  text: string
): UseMiddleEllipsisResult => {
  const containerRef = useRef<E>(null);
  const [displayText, setDisplayText] = useState(text);
  const measurementRef = useRef<HTMLSpanElement | null>(null);

  // Compute the truncated candidate for the current text and container width
  const computeCandidate = useCallback(() => {
    const container = containerRef.current;
    if (!container || !text) return text;
    const MIN_RIGHT_CHARS = 5;
    if (text.length <= MIN_RIGHT_CHARS + 1) {
      return text;
    }

    const containerStyle = window.getComputedStyle(container);
    const textElement =
      container.firstElementChild instanceof HTMLElement ? container.firstElementChild : container;
    const style = window.getComputedStyle(textElement);
    let measurementEl = measurementRef.current;
    if (!measurementEl) {
      measurementEl = document.createElement('span');
      measurementEl.style.position = 'absolute';
      measurementEl.style.visibility = 'hidden';
      measurementEl.style.whiteSpace = 'pre';
      measurementEl.style.pointerEvents = 'none';
      measurementEl.style.left = '-99999px';
      measurementEl.style.top = '0';
      document.body.appendChild(measurementEl);
      measurementRef.current = measurementEl;
    }

    measurementEl.style.font = style.font;
    measurementEl.style.fontSize = style.fontSize;
    measurementEl.style.fontFamily = style.fontFamily;
    measurementEl.style.fontWeight = style.fontWeight;
    measurementEl.style.fontStyle = style.fontStyle;
    measurementEl.style.letterSpacing = style.letterSpacing;
    measurementEl.style.wordSpacing = style.wordSpacing;
    measurementEl.style.textTransform = style.textTransform;
    measurementEl.style.fontKerning = style.fontKerning;
    measurementEl.style.fontFeatureSettings = style.fontFeatureSettings;
    measurementEl.style.fontVariantLigatures = style.fontVariantLigatures;

    const horizontalPadding =
      parseFloat(containerStyle.paddingLeft || '0') +
      parseFloat(containerStyle.paddingRight || '0');
    const parent = container.parentElement;
    const parentStyle = parent ? window.getComputedStyle(parent) : null;
    const parentHorizontalPadding = parentStyle
      ? parseFloat(parentStyle.paddingLeft || '0') + parseFloat(parentStyle.paddingRight || '0')
      : 0;
    const parentContentWidth = parent
      ? Math.max(0, parent.getBoundingClientRect().width - parentHorizontalPadding)
      : 0;
    const maxWidthPx = parsePixelSize(containerStyle.maxWidth);
    const maxWidthContent =
      maxWidthPx !== null && maxWidthPx > 0 ? Math.max(0, maxWidthPx - horizontalPadding) : 0;
    const selfContentWidth = Math.max(
      0,
      container.getBoundingClientRect().width - horizontalPadding
    );
    const externalConstraint = [parentContentWidth, maxWidthContent]
      .filter((w) => w > 0)
      .reduce((min, w) => Math.min(min, w), Number.POSITIVE_INFINITY);
    // Let the value grow beyond the current rendered text width, but never beyond external constraints.
    const constraintWidth = Number.isFinite(externalConstraint)
      ? Math.max(selfContentWidth, externalConstraint)
      : selfContentWidth;
    // Keep a tiny safety margin to avoid edge clipping from sub-pixel rendering differences.
    const available = Math.max(0, constraintWidth - 2);

    if (available <= 0) {
      return text;
    }

    const measureCache = new Map<string, number>();
    const measure = (str: string) => {
      const cached = measureCache.get(str);
      if (cached !== undefined) return cached;
      measurementEl.textContent = str;
      const width = measurementEl.getBoundingClientRect().width;
      measureCache.set(str, width);
      return width;
    };

    if (measure(text) <= available) {
      return text;
    }

    const ellipsis = '\u2026';

    const makeCandidate = (l: number, r: number) =>
      text.slice(0, l) + ellipsis + text.slice(text.length - r);

    const fits = (l: number, r: number) => measure(makeCandidate(l, r)) <= available;

    let leftChars = 0;
    let rightChars = MIN_RIGHT_CHARS;

    // If minimum suffix cannot fit, reduce suffix as a last resort to prevent clipping.
    if (!fits(leftChars, rightChars)) {
      while (rightChars > 1 && !fits(0, rightChars)) {
        rightChars--;
      }
      return makeCandidate(0, rightChars);
    }

    // Keep at least one hidden character so we truly truncate.
    const maxVisibleChars = text.length - 1;
    while (leftChars + rightChars < maxVisibleChars) {
      const nextLeft = leftChars + 1;
      const nextRight = rightChars + 1;

      const canGrowLeft = nextLeft + rightChars <= maxVisibleChars && fits(nextLeft, rightChars);
      const canGrowRight = leftChars + nextRight <= maxVisibleChars && fits(leftChars, nextRight);

      if (!canGrowLeft && !canGrowRight) {
        break;
      }

      if (canGrowLeft && !canGrowRight) {
        leftChars = nextLeft;
      } else if (!canGrowLeft && canGrowRight) {
        rightChars = nextRight;
      } else {
        // Prefer growing the suffix when both options fit.
        if (rightChars <= leftChars + 2) {
          rightChars = nextRight;
        } else {
          leftChars = nextLeft;
        }
      }
    }

    // Final safety pass to guarantee no visual overflow.
    while (!fits(leftChars, rightChars) && (leftChars > 0 || rightChars > 1)) {
      if (leftChars > 0 && (rightChars <= MIN_RIGHT_CHARS || leftChars >= rightChars - 1)) {
        leftChars--;
      } else {
        rightChars--;
      }
    }

    return makeCandidate(leftChars, rightChars);
  }, [text]);

  const recompute = useCallback(() => {
    const candidate = computeCandidate();
    setDisplayText((prev) => (prev === candidate ? prev : candidate));
  }, [computeCandidate]);

  // Recompute on text changes.
  useLayoutEffect(() => {
    recompute();
  }, [text, recompute]);

  // Recompute whenever container size changes.
  useLayoutEffect(() => {
    const container = containerRef.current;
    if (!container) return;
    const parent = container.parentElement;
    const textElement =
      container.firstElementChild instanceof HTMLElement ? container.firstElementChild : null;

    let rafId = 0;
    const scheduleRecompute = () => {
      cancelAnimationFrame(rafId);
      rafId = requestAnimationFrame(() => {
        recompute();
      });
    };

    if (typeof ResizeObserver !== 'undefined') {
      const observer = new ResizeObserver(scheduleRecompute);
      observer.observe(container);
      if (parent) {
        observer.observe(parent);
      }
      if (textElement) {
        observer.observe(textElement);
      }

      const fonts = document.fonts;
      if (fonts?.addEventListener) {
        fonts.addEventListener('loadingdone', scheduleRecompute);
        fonts.addEventListener('loadingerror', scheduleRecompute);
      }

      return () => {
        cancelAnimationFrame(rafId);
        observer.disconnect();
        if (fonts?.removeEventListener) {
          fonts.removeEventListener('loadingdone', scheduleRecompute);
          fonts.removeEventListener('loadingerror', scheduleRecompute);
        }
      };
    }

    window.addEventListener('resize', scheduleRecompute);
    return () => {
      cancelAnimationFrame(rafId);
      window.removeEventListener('resize', scheduleRecompute);
    };
  }, [recompute]);

  // Recompute when typography/style classes change without a geometry resize event.
  useLayoutEffect(() => {
    const container = containerRef.current;
    if (!container || typeof MutationObserver === 'undefined') return;
    const textElement =
      container.firstElementChild instanceof HTMLElement ? container.firstElementChild : null;

    let rafId = 0;
    const scheduleRecompute = () => {
      cancelAnimationFrame(rafId);
      rafId = requestAnimationFrame(() => {
        recompute();
      });
    };

    const observer = new MutationObserver(scheduleRecompute);
    observer.observe(container, { attributes: true, attributeFilter: ['class', 'style'] });
    if (textElement) {
      observer.observe(textElement, { attributes: true, attributeFilter: ['class', 'style'] });
    }

    return () => {
      cancelAnimationFrame(rafId);
      observer.disconnect();
    };
  }, [recompute]);

  useLayoutEffect(() => {
    return () => {
      if (measurementRef.current?.parentNode) {
        measurementRef.current.parentNode.removeChild(measurementRef.current);
      }
      measurementRef.current = null;
    };
  }, []);

  return { ref: containerRef, truncatedText: displayText };
};

export { useMiddleEllipsis };
